   1	<!DOCTYPE html>
   2	<html lang="en">
   3	<head>
   4	<meta charset="UTF-8">
   5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
   6	<title>Concert Simulator</title>
   7	<style>
   8	* { margin: 0; padding: 0; box-sizing: border-box; }
   9	body { background: #0a0a0f; color: #e8e0d0; font-family: 'Georgia', serif; overflow: hidden; height: 100vh; width: 100vw; }
  10	
  11	/* ── SCREENS ── */
  12	.screen { position: absolute; inset: 0; display: none; flex-direction: column; align-items: center; justify-content: center; }
  13	.screen.active { display: flex; }
  14	
  15	/* ── START SCREEN ── */
  16	#start-screen { background: radial-gradient(ellipse at 50% 60%, #1a0a2e 0%, #0a0a0f 70%); }
  17	.start-glow { position: absolute; width: 600px; height: 600px; background: radial-gradient(circle, rgba(120,60,200,0.15) 0%, transparent 70%); top: 50%; left: 50%; transform: translate(-50%,-50%); pointer-events: none; }
  18	.start-title { font-size: 3.2rem; letter-spacing: 0.3em; text-transform: uppercase; color: #fff; text-shadow: 0 0 40px rgba(180,100,255,0.8), 0 0 80px rgba(180,100,255,0.3); margin-bottom: 0.3rem; }
  19	.start-sub { font-size: 0.85rem; letter-spacing: 0.25em; color: #8070a0; text-transform: uppercase; margin-bottom: 3rem; }
  20	.start-tagline { font-size: 1.05rem; color: #c0b0d8; font-style: italic; margin-bottom: 2.5rem; text-align: center; max-width: 420px; line-height: 1.7; }
  21	.btn { background: transparent; border: 1px solid rgba(180,100,255,0.5); color: #d0b8f0; padding: 0.75rem 2.5rem; font-family: inherit; font-size: 0.9rem; letter-spacing: 0.2em; text-transform: uppercase; cursor: pointer; transition: all 0.3s; }
  22	.btn:hover { border-color: rgba(180,100,255,0.9); color: #fff; box-shadow: 0 0 20px rgba(180,100,255,0.3); }
  23	.btn-primary { background: rgba(120,60,200,0.3); border-color: rgba(180,100,255,0.7); }
  24	
  25	/* ── MAIN GAME ── */
  26	#game-screen { background: #0a0a0f; align-items: stretch; justify-content: flex-start; flex-direction: row; }
  27	
  28	/* Sidebar nav */
  29	.sidebar { width: 64px; background: #0e0e16; border-right: 1px solid #1e1e2e; display: flex; flex-direction: column; align-items: center; padding: 1rem 0; gap: 0.5rem; flex-shrink: 0; }
  30	.nav-btn { width: 44px; height: 44px; background: transparent; border: 1px solid transparent; color: #504060; font-size: 1.2rem; cursor: pointer; border-radius: 8px; transition: all 0.2s; display: flex; align-items: center; justify-content: center; position: relative; }
  31	.nav-btn:hover, .nav-btn.active { background: #1a1a2e; border-color: #3a2060; color: #b090e0; }
  32	.nav-btn .tooltip { display: none; position: absolute; left: 52px; background: #1a1a2e; border: 1px solid #3a2060; padding: 0.3rem 0.6rem; font-size: 0.7rem; white-space: nowrap; color: #c0b0d8; border-radius: 4px; letter-spacing: 0.1em; z-index: 100; }
  33	.nav-btn:hover .tooltip { display: block; }
  34	
  35	/* Main content */
  36	.main-content { flex: 1; overflow: hidden; position: relative; }
  37	
  38	/* ── PANELS — NO display on individual IDs, only via .panel / .panel.active ── */
  39	.panel { position: absolute; inset: 0; display: none; flex-direction: column; overflow: hidden; padding-bottom: 48px; }
  40	.panel.active { display: flex; }
  41	.panel-header { padding: 1.5rem 2rem 1rem; border-bottom: 1px solid #1e1e2e; flex-shrink: 0; }
  42	.panel-title { font-size: 0.7rem; letter-spacing: 0.3em; text-transform: uppercase; color: #6050a0; margin-bottom: 0.25rem; }
  43	.panel-heading { font-size: 1.4rem; color: #e0d0f8; }
  44	
  45	/* ── STATUS BAR ── */
  46	.status-bar { position: absolute; bottom: 0; left: 64px; right: 0; height: 48px; background: linear-gradient(to right, #0c0c18, #0e0e16); border-top: 1px solid #1e1e2e; display: flex; align-items: center; padding: 0 1rem; gap: 0; z-index: 50; overflow: hidden; }
  47	.status-item { font-size: 0.72rem; letter-spacing: 0.08em; color: #6050a0; white-space: nowrap; padding: 0 0.8rem; border-right: 1px solid #1e1e2e; }
  48	.status-item:last-child { border-right: none; }
  49	.status-item span { color: #d0c0e8; font-weight: 600; }
  50	.status-week { color: #a090d0; font-size: 0.75rem; letter-spacing: 0.12em; white-space: nowrap; font-style:italic; padding-right: 0.8rem; border-right: 1px solid #1e1e2e; flex-shrink: 0; }
  51	
  52	/* Next Day button in status bar */
  53	.next-day-btn { margin-left: auto; padding: 0.3rem 0.9rem; background: rgba(100,50,180,0.25); border: 1px solid rgba(120,60,200,0.45); color: #b090e0; font-family: inherit; font-size: 0.68rem; letter-spacing: 0.12em; text-transform: uppercase; cursor: pointer; transition: all 0.2s; border-radius: 3px; flex-shrink: 0; }
  54	.next-day-btn:hover { background: rgba(120,60,200,0.45); color: #fff; }
  55	.next-day-btn:disabled { opacity: 0.3; cursor: not-allowed; }
  56	
  57	/* ── BANDBOOK PANEL ── */
  58	.bandbook-tabs { display: flex; gap: 0; border-bottom: 1px solid #1e1e2e; flex-shrink: 0; background: #0e0e16; }
  59	.tab-btn, .bb-tab { padding: 0.7rem 1.4rem; font-family: inherit; font-size: 0.72rem; letter-spacing: 0.15em; text-transform: uppercase; background: transparent; border: none; color: #504060; cursor: pointer; border-bottom: 2px solid transparent; transition: all 0.2s; }
  60	.tab-btn.active, .bb-tab.active { color: #c0a0f0; border-bottom-color: #8060c0; }
  61	.tab-content { flex: 1; overflow: hidden; display:flex; flex-direction:column; }
  62	.tab-pane { display: none; flex:1; flex-direction:column; overflow:hidden; }
  63	.tab-pane.active { display: flex; }
  64	
  65	/* Band cards */
  66	.band-grid { flex:1; overflow:hidden; display:flex; flex-direction:column; }
  67	.band-card { background: #0e0e18; border: 1px solid #1e1e30; border-radius: 4px; padding: 1.2rem; cursor: pointer; transition: all 0.25s; position: relative; overflow: hidden; }
  68	.band-card:hover { border-color: #3a2a60; transform: translateY(-2px); box-shadow: 0 8px 24px rgba(0,0,0,0.4); }
  69	.band-name { font-size: 1rem; color: #e0d0f8; margin-bottom: 0.2rem; letter-spacing: 0.05em; }
  70	.band-genre { font-size: 0.7rem; color: #6050a0; letter-spacing: 0.15em; text-transform: uppercase; margin-bottom: 0.7rem; }
  71	.band-bio { font-size: 0.8rem; color: #9080a8; line-height: 1.6; font-style: italic; margin-bottom: 0.8rem; }
  72	.band-meta { display: flex; justify-content: space-between; align-items: center; }
  73	.band-fee { font-size: 0.75rem; color: #c0a060; letter-spacing: 0.1em; }
  74	.band-traits { display: flex; gap: 0.3rem; flex-wrap: wrap; }
  75	.trait-tag { font-size: 0.6rem; background: #1a1428; border: 1px solid #2a1e48; color: #8070a8; padding: 0.15rem 0.4rem; letter-spacing: 0.08em; border-radius: 2px; }
  76	.band-agent { font-size: 0.68rem; color: #504060; margin-top: 0.5rem; }
  77	.book-btn { margin-top: 0.8rem; width: 100%; padding: 0.5rem; background: rgba(100,50,180,0.2); border: 1px solid rgba(120,60,200,0.4); color: #c0a0f0; font-family: inherit; font-size: 0.72rem; letter-spacing: 0.15em; text-transform: uppercase; cursor: pointer; transition: all 0.2s; }
  78	.book-btn:hover { background: rgba(100,50,180,0.4); border-color: rgba(180,100,255,0.7); color: #fff; }
  79	.book-btn:disabled { opacity: 0.3; cursor: not-allowed; }
  80	
  81	/* ── OFFICE PANEL ── */
  82	.office-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; padding: 1.5rem 2rem; overflow-y: auto; flex: 1; }
  83	.office-card { background: #0e0e18; border: 1px solid #1e1e30; border-radius: 4px; padding: 1.2rem; }
  84	.office-card h3 { font-size: 0.68rem; letter-spacing: 0.2em; text-transform: uppercase; color: #6050a0; margin-bottom: 0.8rem; }
  85	.schedule-slots { overflow-y: auto; flex: 1; padding: 1rem 2rem; }
  86	.schedule-slot { display: flex; justify-content: space-between; align-items: flex-start; padding: 0.45rem 0; border-bottom: 1px solid #1a1a28; font-size: 0.8rem; gap: 0.5rem; }
  87	.schedule-slot:last-child { border-bottom: none; }
  88	.slot-day { color: #7060a0; font-size: 0.72rem; letter-spacing: 0.1em; flex-shrink: 0; }
  89	.slot-act { color: #c0b0d8; text-align: right; }
  90	.slot-empty { color: #302040; font-style: italic; }
  91	.slot-news { color: #806090; font-size: 0.74rem; font-style: italic; text-align: right; max-width: 60%; }
  92	.slot-day-current { color: #c0a0f0; font-weight: bold; }
  93	.finances-row { display: flex; justify-content: space-between; padding: 0.4rem 0; font-size: 0.8rem; border-bottom: 1px solid #1a1a28; }
  94	.finances-row:last-child { border-bottom: none; }
  95	.fin-label { color: #7060a0; }
  96	.fin-value { color: #c0b0d8; }
  97	.fin-value.positive { color: #50c878; }
  98	.fin-value.negative { color: #e05060; }
  99	.notifications-list { display: flex; flex-direction: column; gap: 0.6rem; }
 100	.notif { background: #0a0a14; border-left: 2px solid #3a2060; padding: 0.6rem 0.8rem; font-size: 0.78rem; color: #9080b0; line-height: 1.5; }
 101	.notif.rival { border-left-color: #602020; color: #a07090; }
 102	.notif.good { border-left-color: #205040; color: #80b090; }
 103	.do-show-btn { grid-column: 1/-1; padding: 1rem; background: rgba(100,50,180,0.25); border: 1px solid rgba(120,60,200,0.5); color: #d0b8f0; font-family: inherit; font-size: 0.85rem; letter-spacing: 0.2em; text-transform: uppercase; cursor: pointer; transition: all 0.3s; }
 104	.do-show-btn:hover { background: rgba(100,50,180,0.45); box-shadow: 0 0 30px rgba(120,60,200,0.2); }
 105	.do-show-btn:disabled { opacity: 0.3; cursor: not-allowed; }
 106	
 107	/* ── ENQUIRY SYSTEM ── */
 108	.enquiry-btn { margin-top: 0.8rem; width: 100%; padding: 0.5rem; background: rgba(40,80,140,0.2); border: 1px solid rgba(60,120,200,0.4); color: #90b8f0; font-family: inherit; font-size: 0.72rem; letter-spacing: 0.15em; text-transform: uppercase; cursor: pointer; transition: all 0.2s; }
 109	.enquiry-btn:hover { background: rgba(60,100,180,0.4); border-color: rgba(100,160,255,0.7); color: #fff; }
 110	.enquiry-btn:disabled { opacity: 0.3; cursor: not-allowed; }
 111	.enquiry-btn.pending { background: rgba(80,60,20,0.3); border-color: rgba(160,120,40,0.5); color: #c0a060; cursor: default; }
 112	.enquiry-btn.replied { background: rgba(20,80,40,0.3); border-color: rgba(60,160,80,0.5); color: #60c878; cursor: pointer; }
 113	.msg-entry { background: #0e0e18; border: 1px solid #1e1e30; border-radius: 4px; padding: 1rem; margin-bottom: 0.7rem; }
 114	.msg-from { font-size: 0.72rem; letter-spacing: 0.1em; color: #6050a0; margin-bottom: 0.3rem; text-transform: uppercase; }
 115	.msg-date { font-size: 0.65rem; color: #3a2a50; float: right; }
 116	.msg-text { font-size: 0.82rem; color: #a090c0; line-height: 1.7; }
 117	.msg-actions { margin-top: 0.8rem; display: flex; gap: 0.5rem; }
 118	.msg-btn { flex: 1; padding: 0.4rem 0.6rem; background: rgba(80,40,140,0.2); border: 1px solid rgba(100,60,180,0.4); color: #c0a0f0; font-family: inherit; font-size: 0.65rem; letter-spacing: 0.1em; text-transform: uppercase; cursor: pointer; transition: all 0.2s; border-radius: 2px; }
 119	.msg-btn:hover { background: rgba(100,60,180,0.4); }
 120	.msg-btn.accept { background: rgba(20,80,40,0.3); border-color: rgba(60,160,80,0.5); color: #60c878; }
 121	.msg-btn.accept:hover { background: rgba(30,120,60,0.4); }
 122	.msg-btn.decline { background: rgba(80,20,20,0.2); border-color: rgba(160,60,60,0.4); color: #c06070; }
 123	.msg-btn.decline:hover { background: rgba(120,30,30,0.4); }
 124	
 125	/* ── VENUE UPGRADE CARD ── */
 126	.venue-card { background: linear-gradient(135deg,#0e0e18,#120e20); border: 1px solid #2a1a50; border-radius: 4px; padding: 1.2rem; }
 127	.venue-tier-name { font-size: 1.1rem; color: #d0b8f0; margin-bottom: 0.2rem; }
 128	.venue-tier-cap { font-size: 0.72rem; color: #6050a0; letter-spacing: 0.12em; margin-bottom: 0.8rem; }
 129	.upgrade-row { display: flex; justify-content: space-between; align-items: center; margin-top: 0.8rem; }
 130	.upgrade-cost { font-size: 0.75rem; color: #c0a060; }
 131	.upgrade-btn { padding: 0.4rem 1rem; background: rgba(120,60,200,0.2); border: 1px solid rgba(180,100,255,0.4); color: #c0a0f0; font-family: inherit; font-size: 0.7rem; letter-spacing: 0.12em; text-transform: uppercase; cursor: pointer; transition: all 0.2s; border-radius: 2px; }
 132	.upgrade-btn:hover { background: rgba(120,60,200,0.5); }
 133	.upgrade-btn:disabled { opacity: 0.3; cursor: not-allowed; }
 134	
 135	/* ── SFX EQUIPMENT PANEL ── */
 136	.sfx-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(220px,1fr)); gap: 1rem; padding: 1.5rem 2rem; overflow-y: auto; flex: 1; }
 137	.sfx-card { background: #0e0e18; border: 1px solid #1e1e30; border-radius: 4px; padding: 1.1rem; transition: all 0.2s; }
 138	.sfx-card.owned { border-color: rgba(80,200,120,0.3); }
 139	.sfx-card.active-sfx { border-color: rgba(180,100,255,0.6); box-shadow: 0 0 12px rgba(120,60,200,0.25); }
 140	.sfx-icon { font-size: 1.8rem; margin-bottom: 0.5rem; }
 141	.sfx-name { font-size: 0.9rem; color: #e0d0f8; margin-bottom: 0.2rem; }
 142	.sfx-desc { font-size: 0.75rem; color: #7060a0; line-height: 1.5; margin-bottom: 0.8rem; }
 143	.sfx-synergy { font-size: 0.68rem; color: #507060; margin-bottom: 0.3rem; }
 144	.sfx-penalty { font-size: 0.68rem; color: #705040; margin-bottom: 0.8rem; }
 145	.sfx-cost { font-size: 0.72rem; color: #c0a060; margin-bottom: 0.5rem; }
 146	.sfx-actions { display: flex; gap: 0.5rem; }
 147	.sfx-btn { flex: 1; padding: 0.4rem; background: rgba(100,50,180,0.2); border: 1px solid rgba(120,60,200,0.4); color: #c0a0f0; font-family: inherit; font-size: 0.65rem; letter-spacing: 0.1em; text-transform: uppercase; cursor: pointer; transition: all 0.2s; border-radius: 2px; }
 148	.sfx-btn:hover { background: rgba(100,50,180,0.4); }
 149	.sfx-btn:disabled { opacity: 0.3; cursor: not-allowed; }
 150	.sfx-btn.toggle-on { background: rgba(80,200,120,0.15); border-color: rgba(80,200,120,0.4); color: #80e0a0; }
 151	.sfx-btn.toggle-on:hover { background: rgba(80,200,120,0.3); }
 152	
 153	/* ── ACHIEVEMENTS PANEL ── */
 154	.ach-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(260px,1fr)); gap: 1rem; padding: 1.5rem 2rem; overflow-y: auto; flex: 1; }
 155	.ach-card { background: #0e0e18; border: 1px solid #1e1e30; border-radius: 4px; padding: 1.1rem; opacity: 0.45; transition: all 0.3s; }
 156	.ach-card.unlocked { opacity: 1; border-color: rgba(200,160,80,0.5); box-shadow: 0 0 14px rgba(200,140,40,0.2); }
 157	.ach-icon { font-size: 1.6rem; margin-bottom: 0.4rem; }
 158	.ach-name { font-size: 0.9rem; color: #e0d0f8; margin-bottom: 0.2rem; }
 159	.ach-desc { font-size: 0.75rem; color: #7060a0; line-height: 1.5; }
 160	.ach-reward { font-size: 0.68rem; color: #c0a060; margin-top: 0.5rem; font-style: italic; }
 161	.ach-unlocked-date { font-size: 0.65rem; color: #507050; margin-top: 0.4rem; }
 162	
 163	/* Achievement toast */
 164	.ach-toast { position: fixed; bottom: 70px; left: 50%; transform: translateX(-50%) translateY(20px); background: linear-gradient(135deg,#1a1020,#120e18); border: 1px solid rgba(200,160,80,0.6); padding: 0.8rem 1.5rem; border-radius: 4px; font-size: 0.82rem; color: #d0b870; letter-spacing: 0.08em; opacity: 0; transition: all 0.4s; z-index: 999; text-align: center; box-shadow: 0 0 24px rgba(200,140,40,0.3); pointer-events: none; }
 165	.ach-toast.show { opacity: 1; transform: translateX(-50%) translateY(0); }
 166	
 167	/* ── SHOW NIGHT ── */
 168	#show-screen { background: #050508; }
 169	.stage-container { position: relative; width: 100%; max-width: 700px; height: 420px; margin: 0 auto; }
 170	canvas#stage { width: 100%; height: 100%; }
 171	.show-info { text-align: center; margin-top: 1rem; }
 172	.show-band-name { font-size: 1.6rem; color: #e0d0f8; letter-spacing: 0.1em; margin-bottom: 0.3rem; }
 173	.show-genre { font-size: 0.75rem; color: #6050a0; letter-spacing: 0.2em; text-transform: uppercase; }
 174	.show-events { min-height: 60px; max-width: 600px; text-align: center; margin: 1rem auto 0; font-size: 0.85rem; color: #9080b8; font-style: italic; line-height: 1.7; padding: 0 2rem; white-space: pre-line; }
 175	.show-progress-bar { width: 300px; height: 3px; background: #1a1a2e; margin: 1rem auto 0; border-radius: 2px; overflow: hidden; }
 176	.show-progress-fill { height: 100%; background: linear-gradient(90deg, #6030c0, #a060f0); width: 0%; transition: width 0.3s; }
 177	.show-sfx-badges { display: flex; justify-content: center; gap: 0.5rem; margin-top: 0.5rem; flex-wrap: wrap; }
 178	.sfx-badge { display:inline-block; font-size: 0.65rem; background: rgba(120,60,200,0.2); border: 1px solid rgba(120,60,200,0.4); color: #a080d0; padding: 0.2rem 0.5rem; border-radius: 2px; letter-spacing: 0.08em; }
 179	
 180	/* ── POST SHOW ── */
 181	#postshow-screen { background: #07070f; overflow-y: auto; padding: 2rem; }
 182	.postshow-inner { max-width: 600px; margin: 0 auto; }
 183	.postshow-title { font-size: 0.7rem; letter-spacing: 0.3em; text-transform: uppercase; color: #6050a0; margin-bottom: 0.5rem; }
 184	.postshow-band { font-size: 2rem; color: #e0d0f8; margin-bottom: 0.25rem; }
 185	.postshow-night { font-size: 0.8rem; color: #9080b0; margin-bottom: 2rem; }
 186	.ps-headline { font-size:0.62rem; letter-spacing:0.28em; text-transform:uppercase; color:#6050a0; margin-bottom:0.3rem; }
 187	.ps-band-name { font-size:2rem; color:#e0d0f8; margin-bottom:0.15rem; letter-spacing:0.05em; }
 188	.ps-meta { font-size:0.78rem; color:#7060a0; margin-bottom:1.8rem; }
 189	.ps-stars { font-size:1.4rem; color:#c0a040; letter-spacing:0.1em; margin-bottom:0.3rem; }
 190	.ps-score-line { font-size:0.72rem; color:#6050a0; letter-spacing:0.15em; margin-bottom:1.6rem; }
 191	.newspaper { background:#0c0c10; border:1px solid #252530; padding:1.2rem 1.4rem; margin-bottom:1.4rem; position:relative; }
 192	.newspaper::before { content:''; position:absolute; inset:3px; border:1px solid #1a1a28; pointer-events:none; }
 193	.newspaper-source { font-size:0.58rem; letter-spacing:0.22em; text-transform:uppercase; color:#4a3870; margin-bottom:0.6rem; border-bottom:1px solid #1e1e2e; padding-bottom:0.4rem; }
 194	.newspaper-headline { font-size:1rem; color:#c0b0d8; margin-bottom:0.6rem; line-height:1.4; }
 195	.newspaper-body { font-size:0.8rem; color:#7868a0; line-height:1.8; font-style:italic; }
 196	.band-dm { background:#0e0c18; border:1px solid #1e1830; border-left:3px solid #5a3080; padding:1rem 1.2rem; margin-bottom:1.4rem; }
 197	.band-dm-from { font-size:0.6rem; letter-spacing:0.18em; text-transform:uppercase; color:#5040a0; margin-bottom:0.5rem; }
 198	.band-dm-text { font-size:0.82rem; color:#a090c0; line-height:1.7; }
 199	.buzz-section { margin-bottom:1.4rem; }
 200	.buzz-label { font-size:0.6rem; letter-spacing:0.18em; text-transform:uppercase; color:#5040a0; margin-bottom:0.5rem; }
 201	.buzz-bar-wrap { background:#0a0a14; border:1px solid #1e1e2e; border-radius:2px; height:8px; margin-bottom:0.4rem; overflow:hidden; }
 202	.buzz-bar-fill { height:100%; background:linear-gradient(90deg,#4a2080,#9060e0); border-radius:2px; transition:width 1s ease; }
 203	.buzz-change { font-size:0.7rem; color:#8060c0; }
 204	.buzz-change.up { color:#60c880; }
 205	.revenue-breakdown { background: #0e0e18; border: 1px solid #1e1e30; padding: 1.2rem; margin-bottom: 1.5rem; }
 206	.revenue-breakdown h3 { font-size: 0.65rem; letter-spacing: 0.2em; text-transform: uppercase; color: #6050a0; margin-bottom: 0.8rem; }
 207	.rev-row { display: flex; justify-content: space-between; font-size: 0.8rem; padding: 0.3rem 0; border-bottom: 1px solid #1a1a28; }
