1290	function handleNegotiation(enquiryId, choiceIndex){
1291	  const enq=G.enquiries.find(e=>e.id===enquiryId);
1292	  if(!enq||enq.status!=='replied') return;
1293	  const opt=NEGOTIATION_OPTS[choiceIndex];
1294	  const band=BANDS.find(b=>b.id===enq.bandId);
1295	  if(!band) return;
1296	  const bandIdx=BANDS.indexOf(band);
1297	  const isSupport = enq.slot === 'support';
1298	  if(opt.effect==='standard'){
1299	    enq.status='confirmed';
1300	    if(isSupport){ G.support=band.id; addAlert(`✅ ${band.name} confirmed as support act at £${enq.feeOffered}.`); }
1301	    else { G.headliner=bandIdx; addAlert(`✅ ${band.name} confirmed as headliner at £${enq.feeOffered}.`); }
1302	  } else if(opt.effect==='negotiate'){
1303	    const reduced=Math.round(enq.feeOffered*0.85);
1304	    if(Math.random()>0.4){
1305	      enq.feeOffered=reduced; enq.status='confirmed';
1306	      if(isSupport){ G.support=band.id; addAlert(`✅ Negotiated! ${band.name} supporting at £${reduced}.`); }
1307	      else { G.headliner=bandIdx; addAlert(`✅ Negotiated! ${band.name} confirmed at £${reduced}.`); }
1308	    } else {
1309	      enq.status='declined';
1310	      addAlert(`❌ ${band.name}'s agent rejected the lowball. They walked.`);
1311	    }
1312	  } else if(opt.effect==='bonus'){
1313	    enq.status='confirmed';
1314	    G.rep=Math.min(100,G.rep+2);
1315	    if(isSupport){ G.support=band.id; addAlert(`✅ ${band.name} supporting! Guest list sweetener earned +2 REP.`); }
1316	    else { G.headliner=bandIdx; addAlert(`✅ ${band.name} confirmed! Guest list sweetener earned +2 REP.`); }
1317	  } else if(opt.effect==='decline'){
1318	    enq.status='declined';
1319	    addAlert(`📋 Passed on ${band.name}. Enquiry closed.`);
1320	  }
1321	  saveGame(); renderEnquiries(); renderInbox(); renderPlanSupport(); updateStatusBar(); renderOffice();
1322	}
