1963	function resolveRivalry(choice, detail){
1964	  const overlay = document.getElementById('rivalry-overlay');
1965	  overlay.classList.remove('active');
1966	  const headliner = BANDS[G.headliner];
1967	  const oldSupport = BANDS.find(b=>b.id===G.support);
1968	
1969	  if(choice==='drop_support'){
1970	    G.money = Math.max(0, G.money - 50);
1971	    G.support = null;
1972	    addAlert(`💸 ${oldSupport?oldSupport.name:'Support'} paid off and sent home. -£50. ${headliner.name} headlines solo.`);
1973	    addAlert(detail);
1974	  } else if(choice==='no_support'){
1975	    G.support = null;
1976	    addAlert(`🚪 No support tonight. ${headliner.name} plays alone.`);
1977	    addAlert(detail);
1978	  } else if(choice==='replace'){
1979	    const backup = BANDS.find(b=>b.id===detail);
1980	    if(backup){
1981	      G.support = backup.id;
1982	      G.money = Math.max(0, G.money - backup.feeVal);
