1984	      if(backup.backupRisk) addAlert(`⚠️ Risk: "${backup.backupRisk}"`);
1985	    }
1986	  }
1987	  saveGame(); updateStatusBar();
1988	  // Small delay then run the show
1989	  setTimeout(runShow, 400);
